  1	import { type FC, useState } from 'react';
  2	
  3	import {
  4	  Alert,
  5	  Button,
  6	  FileUpload,
  7	  Form,
  8	  FormGroup,
  9	  HelperText,
 10	  HelperTextItem,
 11	  Stack,
 12	  StackItem,
 13	} from '@patternfly/react-core';
 14	import { isEmpty } from '@utils/helpers';
 15	import { useForkliftTranslation } from '@utils/i18n';
 16	
 17	import {
 18	  type OvaFileUploaderProps,
 19	  OvaValidationVariant,
 20	  type UploadOvaResponse,
 21	} from './utils/types';
 22	import { getUploadButtonLabel, uploadOva, validateOvaFileName } from './utils/utils';
 23	
 24	const OvaFileUploader: FC<OvaFileUploaderProps> = ({ provider }) => {
 25	  const { t } = useForkliftTranslation();
 26	  const [file, setFile] = useState<File | undefined>();
 27	  const [filename, setFilename] = useState('');
 28	  const [response, setResponse] = useState<UploadOvaResponse | null>(null);
 29	  const [error, setError] = useState<string | null>(null);
 30	  const [uploading, setUploading] = useState(false);
 31	  const [validation, setValidation] = useState<OvaValidationVariant>(
 32	    OvaValidationVariant.Indeterminate,
 33	  );
 34	
 35	  const handleUpload = async () => {
 36	    if (!file) return;
 37	
 38	    setError(null);
 39	    setUploading(true);
 40	    setResponse(null);
 41	
 42	    try {
 43	      const responseApi = await uploadOva(provider, file);
 44	      setResponse(responseApi);
 45	    } catch (err) {
 46	      setError((err as Error).message);
 47	    } finally {
 48	      setUploading(false);
 49	    }
 50	  };
 51	
 52	  return (
 53	    <Form>
 54	      <FormGroup label={t('Upload local OVA file')} isRequired={false}>
 55	        <FileUpload
 56	          id="ova-file"
 57	          filename={filename}
 58	          onFileInputChange={(_, newFile) => {
 59	            if (newFile) {
 60	              setFile(newFile);
 61	              setFilename(newFile.name);
 62	              setValidation(validateOvaFileName(newFile.name));
 63	            }
 64	          }}
 65	          hideDefaultPreview
 66	          isRequired
 67	          onClearClick={() => {
 68	            setFile(undefined);
 69	            setFilename('');
 70	            setValidation(OvaValidationVariant.Indeterminate);
 71	            setResponse(null);
 72	            setError(null);
 73	          }}
 74	        />
 75	        <HelperText>
 76	          <HelperTextItem variant={validation}>
 77	            {validation === OvaValidationVariant.Error
 78	              ? t('The uploaded file name extension should be .ova')
 79	              : t(
 80	                  "Upload an OVA file which will be added to provider's virtual machines. The uploaded file name extension should be .ova",
 81	                )}
 82	          </HelperTextItem>
 83	        </HelperText>
 84	      </FormGroup>
 85	
 86	      <Stack hasGutter>
 87	        <StackItem>
 88	          <Button
 89	            isLoading={uploading}
 90	            onClick={handleUpload}
 91	            isDisabled={!file || validation === OvaValidationVariant.Error || uploading}
 92	          >
 93	            {getUploadButtonLabel(uploading)}
 94	          </Button>
 95	        </StackItem>
 96	
 97	        {error && (
 98	          <StackItem>
 99	            <Alert variant="danger" title={t('Error')}>
100	              {error}
101	              {response?.message}
102	            </Alert>
103	          </StackItem>
104	        )}
105	
106	        {response && isEmpty(error) && (
107	          <StackItem>
108	            <Alert variant="success" title={t('File uploaded')} />
109	          </StackItem>
110	        )}
111	      </Stack>
112	    </Form>
113	  );
114	};
115	
116	export default OvaFileUploader;

